    match args.command {
        RequestCommand::Start(args) => start_request_branch(
            &git_repo,
            client,
            api_url,
            session_token,
            args.remote,
            args.branch,
            args.title,
        ),
        RequestCommand::Join(args) => join_request_branch(
            &git_repo,
            client,
            api_url,
            session_token,
            args.remote,
            args.id,
        ),
        RequestCommand::Submit(args) => submit_request_branch(
            &git_repo,
            client,
            api_url,
            session_token,
            args.remote,
            args.stake_credits,
        ),
        RequestCommand::Pull(args) => pull_request_branch(
            &git_repo,
            client,
            api_url,
            session_token,
            args.remote,
            args.id,
        ),
        RequestCommand::Push(args) => push_request_branch(
            &git_repo,
            client,
            api_url,
            session_token,
            args.remote,
            args.id,
        ),
        RequestCommand::SyncMain(args) => {
