    let graph = single_file_graph("/README.md", Visibility::Public, "public readme");
    let visibility_events = vec![
        readme_event(
            "vis_1",
            Some("rv1"),
            None,
            Visibility::Private,
            "public readme",
        ),
        readme_event(
            "vis_2",
            Some("rv1"),
            None,

